declare const ort: any;

const MODELS = {
  melspectrogram: "https://openmachinesai.github.io/X/models/melspectrogram.onnx",
  embedding: "https://openmachinesai.github.io/X/models/embedding_model.onnx",
  classifier: "https://openmachinesai.github.io/X/models/hey_jarvis_v0.1.onnx"
};

export class WakeWordDetector {
  isListening: boolean = false;
  isLoaded: boolean = false;
  onWake: () => void;

  private audioContext: AudioContext | null = null;
  private stream: MediaStream | null = null;
  private processor: ScriptProcessorNode | null = null;

  private melSession: any = null;
  private embSession: any = null;
  private clfSession: any = null;

  private audioBuffer: Float32Array = new Float32Array(0);
  private featureBuffer: any[] = []; // Array of embedding tensors

  // OpenWakeWord constants
  private readonly TARGET_SAMPLE_RATE = 16000;
  private readonly CHUNK_SIZE = 1280; // 80ms at 16kHz
  private readonly EMBEDDING_WINDOW = 16; // Number of frames for classifier
  private readonly THRESHOLD = 0.5;

  constructor(onWake: () => void) {
    this.onWake = onWake;
    // Configure ONNX Runtime to use WASM and appropriate paths if needed
    if (typeof ort !== 'undefined') {
        ort.env.wasm.wasmPaths = "https://cdn.jsdelivr.net/npm/onnxruntime-web@1.17.1/dist/";
    }
  }

  async load() {
    if (this.isLoaded) return;

    try {
      console.log("Loading Wake Word Models...");

      // Load all models in parallel
      const [mel, emb, clf] = await Promise.all([
        ort.InferenceSession.create(MODELS.melspectrogram, { executionProviders: ['wasm'] }),
        ort.InferenceSession.create(MODELS.embedding, { executionProviders: ['wasm'] }),
        ort.InferenceSession.create(MODELS.classifier, { executionProviders: ['wasm'] })
      ]);

      this.melSession = mel;
      this.embSession = emb;
      this.clfSession = clf;

      this.isLoaded = true;
      console.log("Wake Word Models Loaded Successfully");
    } catch (e) {
      console.error("Failed to load wake word models:", e);
      throw e;
    }
  }

  async start() {
    if (!this.isLoaded || this.isListening) return;

    try {
      this.stream = await navigator.mediaDevices.getUserMedia({ 
          audio: { 
              echoCancellation: true, 
              noiseSuppression: true, 
              autoGainControl: true,
              channelCount: 1
          } 
      });

      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: this.TARGET_SAMPLE_RATE });

      // Use ScriptProcessor for wide compatibility (AudioWorklet is better but harder to bundle in single file)
      this.processor = this.audioContext.createScriptProcessor(4096, 1, 1);

      const source = this.audioContext.createMediaStreamSource(this.stream);
      source.connect(this.processor);
      this.processor.connect(this.audioContext.destination);

      this.processor.onaudioprocess = (e) => this.handleAudio(e);

      this.isListening = true;
    } catch (e) {
      console.error("Error starting wake word listener:", e);
    }
  }

  stop() {
    this.isListening = false;

    if (this.processor) {
        this.processor.disconnect();
        this.processor.onaudioprocess = null;
        this.processor = null;
    }

    if (this.stream) {
        this.stream.getTracks().forEach(t => t.stop());
        this.stream = null;
    }

    if (this.audioContext) {
        this.audioContext.close();
        this.audioContext = null;
    }

    // Reset buffers
    this.audioBuffer = new Float32Array(0);
    this.featureBuffer = [];
  }

  private async handleAudio(event: AudioProcessingEvent) {
      if (!this.isListening) return;

      const inputData = event.inputBuffer.getChannelData(0);

      // Resample if necessary (though we requested 16k, browser might give 44.1/48k)
      // Note: ScriptProcessor runs at AudioContext sampleRate.
      // If we created AudioContext with 16000, we should get 16000, but Safari/some browsers might ignore it.
      let processedData = inputData;

      if (event.inputBuffer.sampleRate !== this.TARGET_SAMPLE_RATE) {
          processedData = this.downsample(inputData, event.inputBuffer.sampleRate, this.TARGET_SAMPLE_RATE);
      }

      // Append to buffer
      const newBuffer = new Float32Array(this.audioBuffer.length + processedData.length);
      newBuffer.set(this.audioBuffer);
      newBuffer.set(processedData, this.audioBuffer.length);
      this.audioBuffer = newBuffer;

      // Process in chunks of 1280
      while (this.audioBuffer.length >= this.CHUNK_SIZE) {
          const chunk = this.audioBuffer.slice(0, this.CHUNK_SIZE);
          this.audioBuffer = this.audioBuffer.slice(this.CHUNK_SIZE);

          await this.runInference(chunk);
      }
  }

  private downsample(buffer: Float32Array, fromRate: number, toRate: number): Float32Array {
      if (fromRate === toRate) return buffer;
      const ratio = fromRate / toRate;
      const newLength = Math.round(buffer.length / ratio);
      const result = new Float32Array(newLength);

      for (let i = 0; i < newLength; i++) {
          const idx = Math.floor(i * ratio);
          // Simple nearest neighbor/decimation for speed. 
          // For higher quality, linear interpolation would be:
          // result[i] = buffer[idx] + (buffer[Math.min(idx + 1, buffer.length - 1)] - buffer[idx]) * (i * ratio - idx);
          result[i] = buffer[idx]; 
      }
      return result;
  }

  private async runInference(chunk: Float32Array) {
      try {
          // 1. Audio -> Mel Spectrogram
          // Shape expected: [1, 1280]
          const audioTensor = new ort.Tensor('float32', chunk, [1, this.CHUNK_SIZE]);
          const melFeats = await this.melSession.run({ input: audioTensor });
          // melFeats.output is [1, 1, 32, 32] usually

          // 2. Mel -> Embedding
          // Shape expected: [1, 1, 32, 32]
          // Note: The key name might vary, assuming 'input' and 'output' based on standard openWakeWord
          // but we can inspect session.inputNames if needed.
          // Using standard keys:
          const embFeats = await this.embSession.run({ input: melFeats.output || melFeats.mel_spectrogram });
          const embedding = embFeats.output || embFeats.embedding; 
          // embedding is [1, 1, 1, 96] or similar

          // 3. Buffer Embedding
          // We need to flatten it to [1, 1, 96] or just keep the data
          this.featureBuffer.push(embedding);

          if (this.featureBuffer.length > this.EMBEDDING_WINDOW) {
              this.featureBuffer.shift();
          }

          // 4. Run Classifier if buffer full
          if (this.featureBuffer.length === this.EMBEDDING_WINDOW) {
              // Construct input tensor [1, 16, 96]
              // The embeddings are likely Float32Array
              const combinedData = new Float32Array(this.EMBEDDING_WINDOW * 96);
              for (let i = 0; i < this.EMBEDDING_WINDOW; i++) {
                  // embedding data is likely wrapped in the Tensor object
                  combinedData.set(this.featureBuffer[i].data, i * 96);
              }

              const clfInput = new ort.Tensor('float32', combinedData, [1, this.EMBEDDING_WINDOW, 96]);
              const result = await this.clfSession.run({ input: clfInput });
              const probability = result.output.data[0]; // Assuming sigmoid output [0-1]

            //   console.log("Prob:", probability);

              if (probability > this.THRESHOLD) {
                  console.log("Wake Word Detected! Prob:", probability);
                  this.featureBuffer = []; // Clear buffer to prevent double triggers
                  this.onWake();
                  this.stop(); // Stop listening immediately
              }
          }

      } catch (e) {
          console.error("Inference error:", e);
      }
  }
}

import React, { useEffect, useState, useRef } from 'react';
import { Eyes } from './components/Eyes';
import { VisualDisplay } from './components/VisualDisplay';
import { useGeminiLive } from './hooks/useGeminiLive';
import { WakeWordDetector } from './services/wakeWord';
import { AppState, EyeState } from './types';

// Version: 1.6.0 - OpenWakeWord Integration
export default function App() {
  const [hasStarted, setHasStarted] = useState(false);
  const [wakeState, setWakeState] = useState(false); 
  const [isPreparing, setIsPreparing] = useState(false);
  const [isLoadingModels, setIsLoadingModels] = useState(false);
  const [statusText, setStatusText] = useState("");

  const wakeWordRef = useRef<WakeWordDetector | null>(null);
  const holdTimerRef = useRef<any>(null);

  const { connect, disconnect, isAiSpeaking, isThinking, connectionState, visualContent, setVisualContent } = useGeminiLive(
    process.env.API_KEY, 
    () => {
        setWakeState(false);
        setIsPreparing(false);
    }
  );

  // Initialize Wake Word Detector
  useEffect(() => {
    wakeWordRef.current = new WakeWordDetector(() => {
        if (connectionState === AppState.IDLE) {
            setWakeState(true);
            setStatusText("Wake Word Detected!");
        }
    });

    return () => {
        wakeWordRef.current?.stop();
    };
  }, []); // Run once on mount to create instance

  // Model Loading Logic
  const handleStart = async () => {
    if (!wakeWordRef.current) return;

    setIsLoadingModels(true);
    setHasStarted(true);

    try {
        await wakeWordRef.current.load();
        wakeWordRef.current.start();
        setIsLoadingModels(false);
    } catch (e) {
        console.error("Failed to load models", e);
        setStatusText("Model Load Error");
        setIsLoadingModels(false);
        // Optionally fallback or alert user
    }
  };

  // Connection Management
  useEffect(() => {
    let timeoutId: any;

    if (wakeState && connectionState === AppState.IDLE) {
        setIsPreparing(true);
        wakeWordRef.current?.stop(); // Ensure it's stopped before connecting

        // Short delay to ensure mic release
        timeoutId = setTimeout(() => {
            if (wakeState) {
                connect().finally(() => setIsPreparing(false));
            }
        }, 300);

    } else if (!wakeState && hasStarted && !isLoadingModels && connectionState === AppState.IDLE) {
        // Resume listening if we are idle and not connecting
        disconnect(); // Ensure any previous session is cleaned up

        timeoutId = setTimeout(() => {
             if (!wakeState && !isPreparing) {
                wakeWordRef.current?.start();
             }
        }, 800);
    }

    return () => clearTimeout(timeoutId);
  }, [wakeState, hasStarted, isLoadingModels, connectionState]);

  let eyeState = EyeState.IDLE;
  if (connectionState === AppState.ACTIVE) {
      if (isThinking) eyeState = EyeState.THINKING;
      else if (isAiSpeaking) eyeState = EyeState.SPEAKING;
      else eyeState = EyeState.LISTENING;
  } else if (connectionState === AppState.CONNECTING || isPreparing || isLoadingModels) {
      eyeState = EyeState.LISTENING;
  }

  const handlePointerDown = () => {
      if (!hasStarted || isPreparing || isLoadingModels || connectionState !== AppState.IDLE) return;
      holdTimerRef.current = setTimeout(() => {
          setWakeState(true);
          setStatusText("Manual Hold Triggered");
      }, 700);
  };

  const handlePointerUp = () => {
      if (holdTimerRef.current) {
          clearTimeout(holdTimerRef.current);
          holdTimerRef.current = null;
      }
  };

  if (!hasStarted) {
    return (
      <div className="h-screen w-screen bg-black flex flex-col items-center justify-center text-white gap-4">
        <button 
            onClick={handleStart}
            className="px-8 py-4 bg-gray-900 border border-gray-700 rounded-full hover:bg-gray-800 transition-all font-mono text-xl shadow-[0_0_20px_rgba(255,255,255,0.2)]"
        >
          Initialize Airo System
        </button>
        <p className="text-gray-500 text-sm">Vision & Voice Active (v1.6.0)</p>
      </div>
    );
  }

  return (
    <div 
        className="relative h-screen w-screen overflow-hidden select-none bg-black"
        onPointerDown={handlePointerDown}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
    >
      <Eyes state={eyeState} />

      <VisualDisplay 
        data={visualContent} 
        onDismiss={() => setVisualContent(null)} 
      />

      <div className="absolute bottom-6 left-0 right-0 flex flex-col items-center pointer-events-none gap-3 z-10">
          <span className={`inline-block w-2.5 h-2.5 rounded-full transition-all duration-700 ${
              connectionState === AppState.ACTIVE ? 'bg-green-500 shadow-[0_0_15px_#22c55e]' : 
              connectionState === AppState.CONNECTING || isPreparing || isLoadingModels ? 'bg-yellow-500 animate-pulse' : 
              connectionState === AppState.ERROR ? 'bg-red-500' : 'bg-white/5'
          }`}></span>

          <div className="text-gray-500 font-mono text-[10px] uppercase tracking-[0.2em] opacity-60 text-center px-4 max-w-xs truncate">
              {isLoadingModels ? "Loading Neural Models..." : 
               isPreparing ? "Connecting..." : 
               (statusText || "Awaiting 'Hey Airo'")}
          </div>

          {connectionState === AppState.ERROR && (
              <div className="text-red-500 font-mono text-xs animate-pulse bg-red-900/10 px-3 py-1 rounded-full border border-red-900/20">
                  SYSTEM BUSY - RECONNECTING
              </div>
          )}
      </div>
    </div>
  );
}

declare const ort: any;

const MODELS = {
  melspectrogram: "https://openmachinesai.github.io/X/models/melspectrogram.onnx",
  embedding: "https://openmachinesai.github.io/X/models/embedding_model.onnx",
  classifier: "https://openmachinesai.github.io/X/models/hey_jarvis_v0.1.onnx"
};

export class WakeWordDetector {
  isListening: boolean = false;
  isLoaded: boolean = false;
  onWake: () => void;

  private audioContext: AudioContext | null = null;
  private stream: MediaStream | null = null;
  private processor: ScriptProcessorNode | null = null;

  private melSession: any = null;
  private embSession: any = null;
  private clfSession: any = null;

  // Dynamic input names fetched from models
  private melInputName: string = '';
  private embInputName: string = '';
  private clfInputName: string = '';

  private audioBuffer: Float32Array = new Float32Array(0);
  private featureBuffer: any[] = []; // Array of embedding tensors

  // OpenWakeWord constants
  private readonly TARGET_SAMPLE_RATE = 16000;
  private readonly CHUNK_SIZE = 1280; // 80ms at 16kHz
  private readonly EMBEDDING_WINDOW = 16; // Number of frames for classifier
  private readonly THRESHOLD = 0.5;

  constructor(onWake: () => void) {
    this.onWake = onWake;
    // Configure ONNX Runtime to use WASM and appropriate paths if needed
    if (typeof ort !== 'undefined') {
        ort.env.wasm.wasmPaths = "https://cdn.jsdelivr.net/npm/onnxruntime-web@1.17.1/dist/";
    }
  }

  async load() {
    if (this.isLoaded) return;

    try {
      console.log("Loading Wake Word Models...");

      // Load all models in parallel
      const [mel, emb, clf] = await Promise.all([
        ort.InferenceSession.create(MODELS.melspectrogram, { executionProviders: ['wasm'] }),
        ort.InferenceSession.create(MODELS.embedding, { executionProviders: ['wasm'] }),
        ort.InferenceSession.create(MODELS.classifier, { executionProviders: ['wasm'] })
      ]);

      this.melSession = mel;
      this.embSession = emb;
      this.clfSession = clf;

      // Dynamically get input names to avoid "input name missing" errors
      this.melInputName = this.melSession.inputNames[0];
      this.embInputName = this.embSession.inputNames[0];
      this.clfInputName = this.clfSession.inputNames[0];

      this.isLoaded = true;
      console.log(`Wake Word Models Loaded. Inputs: ${this.melInputName}, ${this.embInputName}, ${this.clfInputName}`);
    } catch (e) {
      console.error("Failed to load wake word models:", e);
      throw e;
    }
  }

  async start() {
    if (!this.isLoaded || this.isListening) return;

    try {
      this.stream = await navigator.mediaDevices.getUserMedia({ 
          audio: { 
              echoCancellation: true, 
              noiseSuppression: true, 
              autoGainControl: true,
              channelCount: 1
          } 
      });

      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: this.TARGET_SAMPLE_RATE });

      // Use ScriptProcessor for wide compatibility (AudioWorklet is better but harder to bundle in single file)
      this.processor = this.audioContext.createScriptProcessor(4096, 1, 1);

      const source = this.audioContext.createMediaStreamSource(this.stream);
      source.connect(this.processor);
      this.processor.connect(this.audioContext.destination);

      this.processor.onaudioprocess = (e) => this.handleAudio(e);

      this.isListening = true;
    } catch (e) {
      console.error("Error starting wake word listener:", e);
    }
  }

  stop() {
    this.isListening = false;

    if (this.processor) {
        this.processor.disconnect();
        this.processor.onaudioprocess = null;
        this.processor = null;
    }

    if (this.stream) {
        this.stream.getTracks().forEach(t => t.stop());
        this.stream = null;
    }

    if (this.audioContext) {
        this.audioContext.close();
        this.audioContext = null;
    }

    // Reset buffers
    this.audioBuffer = new Float32Array(0);
    this.featureBuffer = [];
  }

  private async handleAudio(event: AudioProcessingEvent) {
      if (!this.isListening) return;

      const inputData = event.inputBuffer.getChannelData(0);

      // Resample if necessary
      let processedData = inputData;
      if (event.inputBuffer.sampleRate !== this.TARGET_SAMPLE_RATE) {
          processedData = this.downsample(inputData, event.inputBuffer.sampleRate, this.TARGET_SAMPLE_RATE);
      }

      // Append to buffer
      const newBuffer = new Float32Array(this.audioBuffer.length + processedData.length);
      newBuffer.set(this.audioBuffer);
      newBuffer.set(processedData, this.audioBuffer.length);
      this.audioBuffer = newBuffer;

      // Process in chunks of 1280
      while (this.audioBuffer.length >= this.CHUNK_SIZE) {
          const chunk = this.audioBuffer.slice(0, this.CHUNK_SIZE);
          this.audioBuffer = this.audioBuffer.slice(this.CHUNK_SIZE);

          await this.runInference(chunk);
      }
  }

  private downsample(buffer: Float32Array, fromRate: number, toRate: number): Float32Array {
      if (fromRate === toRate) return buffer;
      const ratio = fromRate / toRate;
      const newLength = Math.round(buffer.length / ratio);
      const result = new Float32Array(newLength);

      for (let i = 0; i < newLength; i++) {
          const idx = Math.floor(i * ratio);
          result[i] = buffer[idx]; 
      }
      return result;
  }

  private async runInference(chunk: Float32Array) {
      try {
          // 1. Audio -> Mel Spectrogram
          const audioTensor = new ort.Tensor('float32', chunk, [1, this.CHUNK_SIZE]);
          const melFeeds = { [this.melInputName]: audioTensor };
          const melResults = await this.melSession.run(melFeeds);
          const melOutput = melResults[this.melSession.outputNames[0]];

          // 2. Mel -> Embedding
          const embFeeds = { [this.embInputName]: melOutput };
          const embResults = await this.embSession.run(embFeeds);
          const embedding = embResults[this.embSession.outputNames[0]];

          // 3. Buffer Embedding
          // Flatten data to Float32Array if it isn't already compatible
          this.featureBuffer.push(embedding);

          if (this.featureBuffer.length > this.EMBEDDING_WINDOW) {
              this.featureBuffer.shift();
          }

          // 4. Run Classifier if buffer full
          if (this.featureBuffer.length === this.EMBEDDING_WINDOW) {
              const combinedData = new Float32Array(this.EMBEDDING_WINDOW * 96);
              for (let i = 0; i < this.EMBEDDING_WINDOW; i++) {
                  combinedData.set(this.featureBuffer[i].data, i * 96);
              }

              const clfInput = new ort.Tensor('float32', combinedData, [1, this.EMBEDDING_WINDOW, 96]);
              const clfFeeds = { [this.clfInputName]: clfInput };
              const clfResults = await this.clfSession.run(clfFeeds);

              // Get output (usually index 0)
              const outputName = this.clfSession.outputNames[0];
              const probability = clfResults[outputName].data[0]; 

              if (probability > this.THRESHOLD) {
                  console.log("Wake Word Detected! Prob:", probability);
                  this.featureBuffer = []; 
                  this.onWake();
                  this.stop(); 
              }
          }

      } catch (e) {
          console.error("Inference error:", e);
      }
  }
}

