  // Buffers for features
  // Embedding model expects 76 frames of 32 mels: [1, 76, 32, 1]
  private melFrameBuffer: Float32Array = new Float32Array(76 * 32).fill(0);

  // Classifier expects 16 embedding vectors of size 96: [1, 16, 96]
  private embeddingBuffer: any[] = []; 

  // OpenWakeWord constants
  private readonly TARGET_SAMPLE_RATE = 16000;
  private readonly CHUNK_SIZE = 1280; // 80ms at 16kHz
  private readonly EMBEDDING_WINDOW = 16; 
  private readonly THRESHOLD = 0.5;

  constructor(onWake: () => void) {
    this.onWake = onWake;
    // Configure ONNX Runtime to use WASM
    if (typeof ort !== 'undefined') {
