      this.embSession = emb;
      this.clfSession = clf;

      this.melInputName = this.melSession.inputNames[0];
      this.embInputName = this.embSession.inputNames[0];
      this.clfInputName = this.clfSession.inputNames[0];

      this.isLoaded = true;
      console.log(`Wake Word Models Loaded. Inputs: ${this.melInputName}, ${this.embInputName}, ${this.clfInputName}`);
    } catch (e) {
      console.error("Failed to load wake word models:", e);
      throw e;
    }
  }

  async start() {
    if (!this.isLoaded || this.isListening) return;

    try {
      this.stream = await navigator.mediaDevices.getUserMedia({ 
          audio: { 
              echoCancellation: true, 
              noiseSuppression: true, 
              autoGainControl: true,
              channelCount: 1
          } 
      });

      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: this.TARGET_SAMPLE_RATE });
      this.processor = this.audioContext.createScriptProcessor(4096, 1, 1);

      const source = this.audioContext.createMediaStreamSource(this.stream);
      source.connect(this.processor);
      this.processor.connect(this.audioContext.destination);

      this.processor.onaudioprocess = (e) => this.handleAudio(e);

      this.isListening = true;
    } catch (e) {
      console.error("Error starting wake word listener:", e);
    }
  }

  stop() {
    this.isListening = false;

    if (this.processor) {
        this.processor.disconnect();
        this.processor.onaudioprocess = null;
        this.processor = null;
    }

    if (this.stream) {
        this.stream.getTracks().forEach(t => t.stop());
        this.stream = null;
    }

    if (this.audioContext) {
        this.audioContext.close();
        this.audioContext = null;
    }

    this.audioBuffer = new Float32Array(0);
    this.melFrameBuffer.fill(0);
    this.embeddingBuffer = [];
  }

  private async handleAudio(event: AudioProcessingEvent) {
      if (!this.isListening) return;

      const inputData = event.inputBuffer.getChannelData(0);

      let processedData = inputData;
      if (event.inputBuffer.sampleRate !== this.TARGET_SAMPLE_RATE) {
          processedData = this.downsample(inputData, event.inputBuffer.sampleRate, this.TARGET_SAMPLE_RATE);
      }

      const newBuffer = new Float32Array(this.audioBuffer.length + processedData.length);
      newBuffer.set(this.audioBuffer);
      newBuffer.set(processedData, this.audioBuffer.length);
      this.audioBuffer = newBuffer;

      while (this.audioBuffer.length >= this.CHUNK_SIZE) {
          const chunk = this.audioBuffer.slice(0, this.CHUNK_SIZE);
          this.audioBuffer = this.audioBuffer.slice(this.CHUNK_SIZE);
          await this.runInference(chunk);
      }
  }

  private downsample(buffer: Float32Array, fromRate: number, toRate: number): Float32Array {
      if (fromRate === toRate) return buffer;
      const ratio = fromRate / toRate;
      const newLength = Math.round(buffer.length / ratio);
      const result = new Float32Array(newLength);
      for (let i = 0; i < newLength; i++) {
          result[i] = buffer[Math.floor(i * ratio)]; 
      }
      return result;
  }

  private async runInference(chunk: Float32Array) {
      try {
          // 1. Audio -> Mel Spectrogram
          const audioTensor = new ort.Tensor('float32', chunk, [1, this.CHUNK_SIZE]);
          const melResults = await this.melSession.run({ [this.melInputName]: audioTensor });
          const melOutput = melResults[this.melSession.outputNames[0]]; // [1, 1, Frames, 32]

          // Flatten mel output data to update the buffer
          const melData = melOutput.data; // Float32Array
          // We expect dim 3 to be 32. 
          const frameSize = 32;
          const newFramesCount = melData.length / frameSize;

          // Shift buffer left
          // melFrameBuffer size is 76 * 32
          this.melFrameBuffer.copyWithin(0, newFramesCount * frameSize);

          // Add new data to the end
          const writeOffset = this.melFrameBuffer.length - melData.length;
          if (writeOffset >= 0) {
              this.melFrameBuffer.set(melData, writeOffset);
          } else {
              // If for some reason new data is larger than buffer, just take the end
              this.melFrameBuffer.set(melData.subarray(-this.melFrameBuffer.length));
          }

          // 2. Mel Buffer -> Embedding
          // Reshape buffer to [1, 76, 32, 1] as expected by the embedding model
          const embInput = new ort.Tensor('float32', this.melFrameBuffer, [1, 76, 32, 1]);
          const embResults = await this.embSession.run({ [this.embInputName]: embInput });
          const embedding = embResults[this.embSession.outputNames[0]]; // [1, 1, 1, 96] or [1, 1, 96]

          // 3. Buffer Embedding
          this.embeddingBuffer.push(embedding);
          if (this.embeddingBuffer.length > this.EMBEDDING_WINDOW) {
              this.embeddingBuffer.shift();
          }

          // 4. Run Classifier
          if (this.embeddingBuffer.length === this.EMBEDDING_WINDOW) {
              // Create [1, 16, 96] tensor
              const combinedData = new Float32Array(this.EMBEDDING_WINDOW * 96);
              for (let i = 0; i < this.EMBEDDING_WINDOW; i++) {
                  combinedData.set(this.embeddingBuffer[i].data, i * 96);
              }

              const clfInput = new ort.Tensor('float32', combinedData, [1, this.EMBEDDING_WINDOW, 96]);
              const clfResults = await this.clfSession.run({ [this.clfInputName]: clfInput });
              const probability = clfResults[this.clfSession.outputNames[0]].data[0]; 

              if (probability > this.THRESHOLD) {
                  console.log("Wake Word Detected! Prob:", probability);
                  this.onWake();
                  this.stop(); 
              }
          }

      } catch (e) {
          console.error("Inference error:", e);
      }
  }
}

